import{_ as e,o as r,c as a,a1 as o}from"./chunks/framework.BX4nIuL2.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/5arduino/arduino_basic.md","filePath":"courses/fab-course/doc/5arduino/arduino_basic.md"}'),n={name:"courses/fab-course/doc/5arduino/arduino_basic.md"};function i(d,t,l,s,c,p){return r(),a("div",null,[...t[0]||(t[0]=[o('<h2 id="_1-layout" tabindex="-1">1. Layout <a class="header-anchor" href="#_1-layout" aria-label="Permalink to &quot;1. Layout&quot;">​</a></h2><p><img src="https://gitlab.com/picbed/bed/uploads/88dcd4c744fc2bffefb9d28712d87114/UNO-TH_Rev3e_sch.jpg" alt=""></p><h2 id="_2-software" tabindex="-1">2. Software <a class="header-anchor" href="#_2-software" aria-label="Permalink to &quot;2. Software&quot;">​</a></h2><p>We can download Arduino IDE from <a href="https://www.arduino.cc/en/Main/Software" target="_blank" rel="noreferrer">www.arduino.cc</a> according to your PC&#39;s version and then install by youself. <img src="https://gitlab.com/picbed/bed/uploads/fc43aa8769dd9935106558474b9dc073/arduino_ui.png" alt=""></p><p>In the meantime we can use developers&#39; software as following:</p><ul><li><a href="http://s4a.cat/" target="_blank" rel="noreferrer">S4A</a></li><li><a href="https://www.mblock.cc/zh-cn/" target="_blank" rel="noreferrer">Mblock</a></li><li><a href="https://sourceforge.net/projects/blocklyduinoenhanced/?css-reload=1" target="_blank" rel="noreferrer">BlockyDuino</a></li><li><a href="https://www.motoduino.com/motoblockly/" target="_blank" rel="noreferrer">motoduino/motoblockly</a></li><li><a href="https://bit.webduino.io/blockly/?lang=zh-hant" target="_blank" rel="noreferrer">Webduino Blockly</a></li><li><a href="https://marketplace.visualstudio.com/items?itemName=vsciot-vscode.vscode-arduino" target="_blank" rel="noreferrer">Visual Studio Code extension for Arduino</a></li></ul><h2 id="_3-hardware" tabindex="-1">3. Hardware <a class="header-anchor" href="#_3-hardware" aria-label="Permalink to &quot;3. Hardware&quot;">​</a></h2><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/aduinounor4.png" alt=""></p><p><img src="https://gitlab.com/picbed/bed/uploads/9d4306ae40072cc40857177a01d4f73c/a000066_featured_5.jpg" alt=""></p><table tabindex="0"><thead><tr><th>Difference</th><th style="text-align:center;">R3</th><th style="text-align:center;">R4 Minima</th><th style="text-align:center;">R4 WiFi</th></tr></thead><tbody><tr><td>MCU</td><td style="text-align:center;">ATmega3238p</td><td style="text-align:center;">Arm Cortex- M4</td><td style="text-align:center;">Arm Cortex- M4 +ESP32-S3 Mini</td></tr><tr><td>WiFi Connectivity</td><td style="text-align:center;">NO</td><td style="text-align:center;">YES</td><td style="text-align:center;">YES</td></tr><tr><td>Bluetooth</td><td style="text-align:center;">NO</td><td style="text-align:center;">YES</td><td style="text-align:center;">YES</td></tr><tr><td>12×8 LED Matrix</td><td style="text-align:center;">NO</td><td style="text-align:center;">YES</td><td style="text-align:center;">YES</td></tr><tr><td>CAN Bus</td><td style="text-align:center;">NO</td><td style="text-align:center;">YES</td><td style="text-align:center;">YES</td></tr><tr><td>USB port</td><td style="text-align:center;"></td><td style="text-align:center;">USB-C</td><td style="text-align:center;">USB-C</td></tr><tr><td>Digital I/O Pins</td><td style="text-align:center;">14</td><td style="text-align:center;">14(14-bit)</td><td style="text-align:center;">14(14-bit)</td></tr><tr><td>Analog input pins</td><td style="text-align:center;">6</td><td style="text-align:center;">6</td><td style="text-align:center;">6</td></tr><tr><td>PWM pins</td><td style="text-align:center;">6</td><td style="text-align:center;">6(12-bit)</td><td style="text-align:center;">6(12-bit)</td></tr><tr><td>Input voltage (VIN)</td><td style="text-align:center;">6-20V</td><td style="text-align:center;">6-24 V</td><td style="text-align:center;">6-24 V</td></tr><tr><td>Memory</td><td style="text-align:center;">32 kB Flash, 2 kB RAM</td><td style="text-align:center;">256 kB Flash, 32 kB RAM</td><td style="text-align:center;">256 kB Flash, 32 kB RAM,ESP: 384 kB ROM, 512 kB SRAM</td></tr><tr><td>Clock speed</td><td style="text-align:center;">16 MHz</td><td style="text-align:center;">48 MHz</td><td style="text-align:center;">48 MHz,ESP: 240 MHz</td></tr></tbody></table><p><a href="https://support.arduino.cc/hc/en-us/articles/9350551575964-What-s-the-difference-between-UNO-R3-and-UNO-R4-boards-" target="_blank" rel="noreferrer"> the difference between UNO R3 and UNO R4 boards</a> Arduino Uno is a microcontroller board based on the ATmega328P (datasheet). It has 14 digital input/output pins (of which 6 can be used as PWM outputs), 6 analog inputs, a 16 MHz ceramic resonator (CSTCE16M0V53-R0), a USB connection, a power jack, an ICSP header and a reset button. It contains everything needed to support the microcontroller; simply connect it to a computer with a USB cable or power it with a AC-to-DC adapter or battery to get started.. You can tinker with your Uno without worrying too much about doing something wrong, worst case scenario you can replace the chip for a few dollars and start over again. &quot;Uno&quot; means one in Italian and was chosen to mark the release of Arduino Software (IDE) 1.0. The Uno board and version 1.0 of Arduino Software (IDE) were the reference versions of Arduino, now evolved to newer releases. The Uno board is the first in a series of USB Arduino boards, and the reference model for the Arduino platform; for an extensive list of current, past or outdated boards see the Arduino index of boards <strong>reference from <a href="https://store.arduino.cc/usa/arduino-uno-rev3" target="_blank" rel="noreferrer">arduino.cc</a></strong></p><p>The following is Arduino family</p><p><strong>For Entry Level</strong></p><p><img src="https://gitlab.com/picbed/bed/uploads/fc61573ce94379ade9d85767694ae594/WX20200414-203551_2x.png" alt=""></p><p><strong>Enhanced Features</strong><img src="https://gitlab.com/picbed/bed/uploads/06f5cc98202d7b25f69f2c09bca24463/WX20200414-203618_2x.png" alt=""></p><p><strong>Internet of Things</strong><img src="https://gitlab.com/picbed/bed/uploads/d12b7147bb3be32e74eb2c01125bc710/WX20200414-203634_2x.png" alt=""></p><p><strong>Education</strong><img src="https://gitlab.com/picbed/bed/uploads/a49e751018cf2dc054795a7fca38f72f/WX20200414-203646_2x.png" alt=""></p><h2 id="_3-application" tabindex="-1">3.Application <a class="header-anchor" href="#_3-application" aria-label="Permalink to &quot;3.Application&quot;">​</a></h2><p><a href="https://www.arduino.cc/pro" target="_blank" rel="noreferrer">Arduino pro</a> is a complete low-code IoT application development platform, making digital transformation possible for companies in simple, realistic, and measurable steps <img src="https://gitlab.com/picbed/bed/uploads/e2ef968d0082d3e31fb685c4e83495fe/1586900339815.jpg" alt=""></p><h2 id="_4-component" tabindex="-1">4. Component <a class="header-anchor" href="#_4-component" aria-label="Permalink to &quot;4. Component&quot;">​</a></h2><p>breadboard <img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/Breadboard_Anno.jpeg" alt=""></p><p>Resistor color <img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/resistorcolor.png" alt=""></p><h2 id="_5-others" tabindex="-1">5. Others <a class="header-anchor" href="#_5-others" aria-label="Permalink to &quot;5. Others&quot;">​</a></h2><ol><li><a href="https://www.seeedstudio.com/xiao-series-page" target="_blank" rel="noreferrer">Seeedstudio Xiao</a></li><li><a href="https://m5stack.com/zh-cn/" target="_blank" rel="noreferrer">M5stack</a></li><li><a href="https://www.espressif.com/zh-hans/products/socs/esp32-c2" target="_blank" rel="noreferrer">ESP32</a></li><li><a href="https://www.dfrobot.com" target="_blank" rel="noreferrer">DFrobot</a></li><li><a href="https://medium.com/@thomas.kilmar/arduino-cli-with-visual-studio-code-on-macos-d2ad32ff0276" target="_blank" rel="noreferrer">vscode run Arduino</a></li></ol>',24)])])}const g=e(n,[["render",i]]);export{u as __pageData,g as default};
